import React from "react";
import styles from "./ProductCellListView.module.css";
import { useTranslation } from "react-i18next";
import { Product } from "../../../model/productModel";

interface ProductCellListViewProps {
    product: Product;
}

const ProductCellListView: React.FC<ProductCellListViewProps> = ({ product }) => {
    const { t } = useTranslation<'translation'>();

    return (
        <div className={styles.card}>
            <div className={styles.wrapper}>
                {/* Product Image */}
                <div className={styles.cardImage}>
                    <img src={product.image_main || "assets/default-product.jpg"} alt={product.name} />
                </div>

                {/* Product Content */}
                <div className={styles.content}>
                    <p className={styles.title}>{product.name}</p>
                </div>

                <div className={styles.leftSideContainer}>
                    <div className={styles.priceContainer}>
                        {product.price !== product.price_new && (
                            <p className={`${styles.title} ${styles.price} ${styles.oldPrice}`}>
                                {product.price}
                            </p>
                        )}
                        <p className={`${styles.title} ${styles.price}`}>
                            {product.price_new}
                        </p>
                    </div>
                    <div className={styles.buttonContainer}>
                        <div className={styles.buttonCompare}>
                            <div className={styles.buttonWrapperCompare}>
                                <div className={styles.textCompare}>{t('compare')}</div>
                                <span className={styles.icon}>
                                    {/* SVG Compare Icon */}
                                </span>
                            </div>
                        </div>
                        <div className={styles.button}>
                            <div className={styles.buttonWrapper}>
                                <div className={styles.text}>{t('addToCart')}</div>
                                <span className={styles.icon}>
                                    {/* SVG Cart Icon */}
                                </span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ProductCellListView;
